// components/ArticleFeedback.tsx — simplified React component
// Renders a feedback widget at the bottom of each KB article

import { useState } from 'react';

interface ArticleFeedbackProps {
  articleId: string;
  articleTitle: string;
}

export function ArticleFeedback({ articleId, articleTitle }: ArticleFeedbackProps) {
  const [submitted, setSubmitted] = useState(false);
  const [comment, setComment] = useState('');

  const submitFeedback = async (helpful: boolean) => {
    await fetch('/api/kb-feedback', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        articleId,
        articleTitle,
        helpful,
        comment: comment.trim() || null,
        searchQuery: sessionStorage.getItem('last_kb_search') || null,
        timestamp: new Date().toISOString(),
      }),
    });
    setSubmitted(true);
  };

  if (submitted) {
    return <p className="text-sm text-gray-500">Thanks for your feedback!</p>;
  }

  return (
    <div className="border-t pt-4 mt-8">
      <p className="text-sm font-medium">Was this article helpful?</p>
      <div className="flex gap-3 mt-2">
        <button onClick={() => submitFeedback(true)}>Yes</button>
        <button onClick={() => submitFeedback(false)}>No</button>
      </div>
      <textarea
        placeholder="Optional: what was missing or incorrect?"
        value={comment}
        onChange={e => setComment(e.target.value)}
        className="mt-2 w-full text-sm"
        rows={2}
      />
    </div>
  );
}

# scripts/support_ticket_analysis.py
# Pulls tagged tickets from Zendesk API and aggregates KB feedback signals

import requests, os
from collections import Counter
from datetime import datetime, timedelta

ZENDESK_URL = os.environ["ZENDESK_URL"]
ZENDESK_TOKEN = os.environ["ZENDESK_TOKEN"]

KB_TAGS = ["kb:missing", "kb:inaccurate", "kb:incomplete", "kb:found-unhelpful"]

def get_tagged_tickets(days: int = 30) -> list[dict]:
    since = (datetime.now() - timedelta(days=days)).strftime("%Y-%m-%dT%H:%M:%SZ")
    tickets = []
    page = 1
    while True:
        resp = requests.get(
            f"{ZENDESK_URL}/api/v2/search.json",
            params={
                "query": f"type:ticket tags:{' OR '.join(KB_TAGS)} created>{since}",
                "page": page,
            },
            auth=("support@company.com/token", ZENDESK_TOKEN),
        )
        data = resp.json()
        tickets.extend(data["results"])
        if not data.get("next_page"):
            break
        page += 1
    return tickets

def analyze_kb_signals(tickets: list[dict]) -> dict:
    tag_counts = Counter()
    topic_gaps = Counter()

    for ticket in tickets:
        for tag in ticket.get("tags", []):
            if tag in KB_TAGS:
                tag_counts[tag] += 1
        # Extract topic from ticket subject (simplified; real impl uses NLP)
        subject = ticket.get("subject", "")
        for keyword in ["rate limit", "streaming", "function calling", "token", "pricing"]:
            if keyword.lower() in subject.lower():
                topic_gaps[keyword] += 1

    return {
        "tag_counts": dict(tag_counts),
        "top_topic_gaps": topic_gaps.most_common(10),
        "total_kb_related_tickets": sum(tag_counts.values()),
    }

if __name__ == "__main__":
    import json
    tickets = get_tagged_tickets(days=30)
    analysis = analyze_kb_signals(tickets)
    print(json.dumps(analysis, indent=2))
